import { DynamoDBClient, GetItemCommand, PutItemCommand } from '@aws-sdk/client-dynamodb';
import {
  CognitoIdentityProviderClient,
  CreateGroupCommand,
  DeleteGroupCommand,
  ListUsersInGroupCommand,
} from '@aws-sdk/client-cognito-identity-provider';
import { validateTenantAccess, getTenantIdFromRequest, createResponse, createLogger } from 'admin-auth';

const logger = createLogger('settings');

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });
const cognito = new CognitoIdentityProviderClient({ region: process.env.AWS_REGION });

// Fields from amfaConfigs that we expose in the settings UI
const AMFA_CONFIG_UI_FIELDS = [
  'enable_password_reset',
  'enable_self_service',
  'enable_self_service_remove_buttons',
  'enable_user_registration',
  'enable_have_i_been_pwned',
  'enable_google_recaptcha',
  'recaptcha_key',
  'recaptcha_secret',
  'master_additional_otp_methods',
  'user_registration_default_group',
  'update_profile_force_mobile_token_first_if_registered',
  'enable_password_expire',
  'passwords_expire_days',
  'enable_prevent_password_reuse',
  'prevent_password_reuse_count',
  'enable_auto_pwd_reset_on_threat',
];

// Fields from amfaLegals
const LEGAL_FIELDS = [
  'terms_of_service',
  'privacy_policy',
];

// Fields from amfaBrandings (Login Service branding)
const BRANDING_FIELDS = [
  'service_name',
  'mobile_token_svc_name',
  'logo_url',
  'email_logo_url',
  'brand_base_color',
  'favicon_url',
];

/** Special policy groups (contain '-') cannot be deleted */
const isSpecialPolicyGroup = (groupName) => groupName.includes('-');

const fetchConfig = async (configType, tenantId) => {
  const params = {
    TableName: process.env.AMFACONFIG_TABLE,
    Key: {
      id: { S: tenantId },
      configtype: { S: configType },
    },
  };
  const result = await dynamodb.send(new GetItemCommand(params));
  if (result.Item?.value?.S) {
    return JSON.parse(result.Item.value.S);
  }
  return null;
};

const saveConfig = async (configType, tenantId, value) => {
  const params = {
    TableName: process.env.AMFACONFIG_TABLE,
    Item: {
      id: { S: tenantId },
      configtype: { S: configType },
      value: { S: JSON.stringify(value) },
    },
  };
  await dynamodb.send(new PutItemCommand(params));
};

/**
 * Build response from all config types
 */
const buildSettingsResponse = (amfaConfigs, amfaLegals, amfaBrandings) => {
  const settings = {};

  if (amfaConfigs) {
    AMFA_CONFIG_UI_FIELDS.forEach(field => {
      if (amfaConfigs[field] !== undefined) {
        settings[field] = amfaConfigs[field];
      }
    });
  }

  if (amfaLegals) {
    LEGAL_FIELDS.forEach(field => {
      if (amfaLegals[field] !== undefined) {
        settings[field] = amfaLegals[field];
      }
    });
  }

  if (amfaBrandings) {
    BRANDING_FIELDS.forEach(field => {
      if (amfaBrandings[field] !== undefined) {
        settings[field] = amfaBrandings[field];
      }
    });
  }

  return settings;
};

/**
 * Apply UI settings back to config objects, preserving non-UI fields
 */
const applySettingsToConfigs = (settings, existingAmfaConfigs, existingAmfaLegals, existingAmfaBrandings) => {
  const updatedAmfaConfigs = { ...(existingAmfaConfigs || {}) };
  AMFA_CONFIG_UI_FIELDS.forEach(field => {
    if (settings[field] !== undefined) {
      updatedAmfaConfigs[field] = settings[field];
    }
  });

  const updatedAmfaLegals = { ...(existingAmfaLegals || {}) };
  LEGAL_FIELDS.forEach(field => {
    if (settings[field] !== undefined) {
      updatedAmfaLegals[field] = settings[field];
    }
  });

  const updatedAmfaBrandings = { ...(existingAmfaBrandings || {}) };
  BRANDING_FIELDS.forEach(field => {
    if (settings[field] !== undefined) {
      updatedAmfaBrandings[field] = settings[field];
    }
  });

  return { updatedAmfaConfigs, updatedAmfaLegals, updatedAmfaBrandings };
};

/**
 * Sync Cognito user groups with policy changes.
 * - New normal policy groups → CreateGroup
 * - Deleted normal policy groups → DeleteGroup (only if empty)
 * Special policy groups (containing '-') are never synced with Cognito.
 */
const syncCognitoGroups = async (oldPolicies, newPolicies, userPoolId) => {
  const oldNormalGroups = Object.keys(oldPolicies || {}).filter(g => !isSpecialPolicyGroup(g));
  const newNormalGroups = Object.keys(newPolicies || {}).filter(g => !isSpecialPolicyGroup(g));

  const added = newNormalGroups.filter(g => !oldNormalGroups.includes(g));
  const removed = oldNormalGroups.filter(g => !newNormalGroups.includes(g));

  const results = { created: [], deleted: [], errors: [] };

  // Create new groups
  for (const groupName of added) {
    try {
      await cognito.send(new CreateGroupCommand({
        UserPoolId: userPoolId,
        GroupName: groupName,
        Description: `Policy group (rank: ${newPolicies[groupName]?.rank || 'N/A'})`,
      }));
      results.created.push(groupName);
      logger.info(`Created Cognito group: ${groupName}`);
    } catch (err) {
      if (err.name === 'GroupExistsException') {
        logger.info(`Cognito group already exists: ${groupName}`);
      } else {
        logger.error(`Failed to create group ${groupName}:`, err.message);
        results.errors.push({ group: groupName, action: 'create', error: err.message });
      }
    }
  }

  // Delete removed groups (only if no users in them)
  for (const groupName of removed) {
    try {
      // Check if group has users
      const usersInGroup = await cognito.send(new ListUsersInGroupCommand({
        UserPoolId: userPoolId,
        GroupName: groupName,
        Limit: 1,
      }));

      if (usersInGroup.Users && usersInGroup.Users.length > 0) {
        logger.warn(`Cannot delete group ${groupName}: has users`);
        results.errors.push({
          group: groupName,
          action: 'delete',
          error: 'Group has users. Remove users from group first.',
        });
        continue;
      }

      await cognito.send(new DeleteGroupCommand({
        UserPoolId: userPoolId,
        GroupName: groupName,
      }));
      results.deleted.push(groupName);
      logger.info(`Deleted Cognito group: ${groupName}`);
    } catch (err) {
      if (err.name === 'ResourceNotFoundException') {
        logger.info(`Cognito group not found (already deleted): ${groupName}`);
      } else {
        logger.error(`Failed to delete group ${groupName}:`, err.message);
        results.errors.push({ group: groupName, action: 'delete', error: err.message });
      }
    }
  }

  return results;
};

export const handler = async (event) => {
  console.info("Settings Lambda EVENT\n" + JSON.stringify(event, null, 2));

  const tenantId = getTenantIdFromRequest(event) || event.pathParameters?.id;

  if (!tenantId) {
    return createResponse(400, { error: 'tenant_id required in request' });
  }

  const authResult = await validateTenantAccess(event, tenantId);
  if (!authResult.authorized) {
    return createResponse(authResult.statusCode, { error: authResult.error });
  }

  const { userPoolId } = authResult;
  logger.info(`Authorized access for tenant ${tenantId}`);

  const httpMethod = event.requestContext?.http?.method || event.httpMethod || 'GET';

  try {
    if (httpMethod === 'GET') {
      const [amfaConfigs, amfaLegals, amfaBrandings, amfaPolicies] = await Promise.all([
        fetchConfig('amfaConfigs', tenantId),
        fetchConfig('amfaLegals', tenantId),
        fetchConfig('amfaBrandings', tenantId),
        fetchConfig('amfaPolicies', tenantId),
      ]);

      const settings = buildSettingsResponse(amfaConfigs, amfaLegals, amfaBrandings);
      return createResponse(200, { data: { ...settings, policies: amfaPolicies || {} } });

    } else if (httpMethod === 'PUT') {
      const body = typeof event.body === 'string' ? JSON.parse(event.body) : event.body;
      const incomingSettings = body.data;

      if (!incomingSettings) {
        return createResponse(400, { error: 'Missing data in request body' });
      }

      const [existingAmfaConfigs, existingAmfaLegals, existingAmfaBrandings, existingPolicies] = await Promise.all([
        fetchConfig('amfaConfigs', tenantId),
        fetchConfig('amfaLegals', tenantId),
        fetchConfig('amfaBrandings', tenantId),
        fetchConfig('amfaPolicies', tenantId),
      ]);

      // Apply settings (non-policy fields)
      const { updatedAmfaConfigs, updatedAmfaLegals, updatedAmfaBrandings } = applySettingsToConfigs(
        incomingSettings,
        existingAmfaConfigs,
        existingAmfaLegals,
        existingAmfaBrandings
      );

      const savePromises = [
        saveConfig('amfaConfigs', tenantId, updatedAmfaConfigs),
        saveConfig('amfaLegals', tenantId, updatedAmfaLegals),
        saveConfig('amfaBrandings', tenantId, updatedAmfaBrandings),
      ];

      // Handle policies if provided
      let syncResults = null;
      if (incomingSettings.policies !== undefined) {
        const newPolicies = incomingSettings.policies;

        // Validate: special policy groups cannot be deleted
        const oldSpecial = Object.keys(existingPolicies || {}).filter(g => isSpecialPolicyGroup(g));
        const newKeys = Object.keys(newPolicies);
        const deletedSpecial = oldSpecial.filter(g => !newKeys.includes(g));
        if (deletedSpecial.length > 0) {
          return createResponse(400, {
            error: `Cannot delete special policy groups: ${deletedSpecial.join(', ')}`,
          });
        }

        // Sync Cognito groups (create/delete)
        syncResults = await syncCognitoGroups(existingPolicies, newPolicies, userPoolId);

        // If any group deletion failed because of users, return error
        const blockingErrors = syncResults.errors.filter(e => e.action === 'delete');
        if (blockingErrors.length > 0) {
          return createResponse(409, {
            error: 'Some groups could not be deleted',
            details: blockingErrors,
          });
        }

        savePromises.push(saveConfig('amfaPolicies', tenantId, newPolicies));
      }

      await Promise.all(savePromises);

      const settings = buildSettingsResponse(updatedAmfaConfigs, updatedAmfaLegals, updatedAmfaBrandings);
      const updatedPolicies = incomingSettings.policies !== undefined
        ? incomingSettings.policies
        : (existingPolicies || {});

      return createResponse(200, {
        data: { ...settings, policies: updatedPolicies },
        ...(syncResults && { groupSync: syncResults }),
      });

    } else {
      return createResponse(405, { error: `Method ${httpMethod} not allowed` });
    }
  } catch (err) {
    logger.error('Settings Lambda error:', err);
    return createResponse(500, { type: 'exception', message: err.message || 'Internal server error' });
  }
};
